// Load mock inventory data for wholesale distributor demo
const inventory = [
  { sku: "SAF-001", name: "Hard Hats (Class E)", category: "Safety", current_stock: 12, reorder_threshold: 25, max_stock: 100, unit_cost: 18.50, supplier: "SafeGuard Industrial", supplier_email: "jtsomwaru+supplier1@gmail.com" },
  { sku: "SAF-002", name: "Cut-Resistant Gloves (L)", category: "Safety", current_stock: 8, reorder_threshold: 30, max_stock: 120, unit_cost: 12.75, supplier: "SafeGuard Industrial", supplier_email: "jtsomwaru+supplier1@gmail.com" },
  { sku: "SAF-003", name: "Safety Vests (Hi-Vis Orange)", category: "Safety", current_stock: 45, reorder_threshold: 20, max_stock: 80, unit_cost: 8.25, supplier: "SafeGuard Industrial", supplier_email: "jtsomwaru+supplier1@gmail.com" },
  { sku: "SAF-004", name: "Safety Glasses (ANSI Z87)", category: "Safety", current_stock: 6, reorder_threshold: 40, max_stock: 150, unit_cost: 4.50, supplier: "SafeGuard Industrial", supplier_email: "jtsomwaru+supplier1@gmail.com" },
  { sku: "PKG-001", name: "Stretch Wrap Film (18\")", category: "Packaging", current_stock: 3, reorder_threshold: 10, max_stock: 50, unit_cost: 32.00, supplier: "Metro Packaging Co", supplier_email: "jtsomwaru+supplier2@gmail.com" },
  { sku: "PKG-002", name: "Shipping Tape (2\" x 110 yd)", category: "Packaging", current_stock: 22, reorder_threshold: 15, max_stock: 60, unit_cost: 3.85, supplier: "Metro Packaging Co", supplier_email: "jtsomwaru+supplier2@gmail.com" },
  { sku: "PKG-003", name: "Corrugated Boxes (12x12x12)", category: "Packaging", current_stock: 4, reorder_threshold: 20, max_stock: 100, unit_cost: 1.95, supplier: "Metro Packaging Co", supplier_email: "jtsomwaru+supplier2@gmail.com" },
  { sku: "CLN-001", name: "Industrial Degreaser (Gal)", category: "Cleaning", current_stock: 15, reorder_threshold: 10, max_stock: 40, unit_cost: 14.50, supplier: "CleanPro Supplies", supplier_email: "jtsomwaru+supplier3@gmail.com" },
  { sku: "CLN-002", name: "Microfiber Mop Heads", category: "Cleaning", current_stock: 2, reorder_threshold: 12, max_stock: 48, unit_cost: 6.75, supplier: "CleanPro Supplies", supplier_email: "jtsomwaru+supplier3@gmail.com" },
  { sku: "CLN-003", name: "Paper Towels (Case/30 rolls)", category: "Cleaning", current_stock: 8, reorder_threshold: 8, max_stock: 32, unit_cost: 42.00, supplier: "CleanPro Supplies", supplier_email: "jtsomwaru+supplier3@gmail.com" },
  { sku: "PWR-001", name: "Drill Bits Set (29-pc)", category: "Tools", current_stock: 18, reorder_threshold: 10, max_stock: 40, unit_cost: 28.50, supplier: "ProTool Wholesale", supplier_email: "jtsomwaru+supplier4@gmail.com" },
  { sku: "PWR-002", name: "Reciprocating Saw Blades (10-pk)", category: "Tools", current_stock: 5, reorder_threshold: 15, max_stock: 60, unit_cost: 22.00, supplier: "ProTool Wholesale", supplier_email: "jtsomwaru+supplier4@gmail.com" },
  { sku: "PWR-003", name: "Extension Cords (50ft, 12 AWG)", category: "Tools", current_stock: 9, reorder_threshold: 8, max_stock: 30, unit_cost: 34.00, supplier: "ProTool Wholesale", supplier_email: "jtsomwaru+supplier4@gmail.com" },
  { sku: "ELC-001", name: "Wire Connectors (100-pk)", category: "Electrical", current_stock: 1, reorder_threshold: 20, max_stock: 80, unit_cost: 8.95, supplier: "NYC Electric Supply", supplier_email: "jtsomwaru+supplier5@gmail.com" },
  { sku: "ELC-002", name: "Electrical Tape (10-pk)", category: "Electrical", current_stock: 14, reorder_threshold: 10, max_stock: 40, unit_cost: 11.50, supplier: "NYC Electric Supply", supplier_email: "jtsomwaru+supplier5@gmail.com" }
];

const triggerData = $input.first().json;

return [{
  json: {
    trigger: triggerData.trigger || 'manual',
    triggered_by: triggerData.triggered_by || 'api',
    date: triggerData.date || new Date().toISOString().split('T')[0],
    inventory: inventory,
    total_skus: inventory.length
  }
}];

// Build the Claude AI prompt for inventory analysis
const data = $input.first().json;
const inventory = data.inventory;

// Format inventory table for Claude
let inventoryTable = 'Current Inventory Status:\n';
inventoryTable += '| SKU | Name | Category | Stock | Threshold | Gap | Supplier |\n';
inventoryTable += '|-----|------|----------|-------|-----------|-----|----------|\n';

for (const item of inventory) {
  const gap = item.current_stock - item.reorder_threshold;
  const gapStr = gap < 0 ? gap.toString() : '+' + gap;
  inventoryTable += `| ${item.sku} | ${item.name} | ${item.category} | ${item.current_stock} | ${item.reorder_threshold} | ${gapStr} | ${item.supplier} |\n`;
}

const systemPrompt = 'You are an inventory management AI for a wholesale distributor. Analyze the provided inventory data and identify items that need to be reordered. Return ONLY valid JSON — no markdown, no explanation, no code blocks, just the raw JSON object.';

const userPrompt = inventoryTable + `

Analyze this inventory and identify items AT or BELOW their reorder threshold (current_stock <= reorder_threshold).

Urgency rules:
- stock = 0-25% of threshold → critical
- stock = 26-50% of threshold → high  
- stock = 51-100% of threshold → medium
- exactly at threshold → medium

Order quantity: max_stock minus current_stock

Return a JSON object with this exact structure:
{
  "analysis_summary": "2-3 sentence executive summary",
  "reorder_items": [
    {
      "sku": "",
      "name": "",
      "category": "",
      "current_stock": 0,
      "reorder_threshold": 0,
      "suggested_order_qty": 0,
      "urgency": "critical|high|medium",
      "unit_cost": 0,
      "estimated_po_value": 0,
      "supplier": "",
      "supplier_email": "",
      "reasoning": ""
    }
  ],
  "reorder_count": 0,
  "total_po_value": 0,
  "critical_count": 0
}`;

const requestBody = {
  model: 'anthropic/claude-3.5-sonnet',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  max_tokens: 4000,
  temperature: 0.1
};

return [{
  json: {
    ...data,
    ai_request_body: requestBody
  }
}];

// Parse Claude's JSON response and extract reorder items
const upstreamData = $('Build AI Prompt').item.json;
const aiResponse = $input.first().json;

let analysis;
try {
  // Extract content from OpenRouter response
  const content = aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message && aiResponse.choices[0].message.content
    ? aiResponse.choices[0].message.content
    : '';

  // Clean any markdown code blocks if present
  let cleanContent = content.trim();
  if (cleanContent.startsWith('```json')) {
    cleanContent = cleanContent.slice(7);
  } else if (cleanContent.startsWith('```')) {
    cleanContent = cleanContent.slice(3);
  }
  if (cleanContent.endsWith('```')) {
    cleanContent = cleanContent.slice(0, -3);
  }
  cleanContent = cleanContent.trim();

  analysis = JSON.parse(cleanContent);
} catch (e) {
  // Fallback if parsing fails
  analysis = {
    analysis_summary: 'Error parsing AI response',
    reorder_items: [],
    reorder_count: 0,
    total_po_value: 0,
    critical_count: 0,
    parse_error: e.message
  };
}

// Group items by supplier for PO generation
const itemsBySupplier = {};
if (analysis.reorder_items && Array.isArray(analysis.reorder_items)) {
  for (const item of analysis.reorder_items) {
    const supplier = item.supplier || 'Unknown';
    if (!itemsBySupplier[supplier]) {
      itemsBySupplier[supplier] = {
        supplier: supplier,
        supplier_email: item.supplier_email || '',
        items: [],
        subtotal: 0
      };
    }
    itemsBySupplier[supplier].items.push(item);
    itemsBySupplier[supplier].subtotal += item.estimated_po_value || 0;
  }
}

return [{
  json: {
    trigger: upstreamData.trigger,
    triggered_by: upstreamData.triggered_by,
    date: upstreamData.date,
    total_skus: upstreamData.total_skus,
    analysis_summary: analysis.analysis_summary,
    reorder_items: analysis.reorder_items || [],
    reorder_count: analysis.reorder_count || 0,
    total_po_value: analysis.total_po_value || 0,
    critical_count: analysis.critical_count || 0,
    items_by_supplier: itemsBySupplier,
    supplier_count: Object.keys(itemsBySupplier).length,
    ai_model: 'claude-3.5-sonnet',
    ai_tokens_used: aiResponse.usage ? aiResponse.usage.total_tokens : 0
  }
}];

// Format Purchase Orders grouped by supplier
const data = $('Parse AI Response').item.json;
const itemsBySupplier = data.items_by_supplier;
const poDate = data.date;

const pos = [];
let poNumber = 1;

for (const supplierName of Object.keys(itemsBySupplier)) {
  const supplierData = itemsBySupplier[supplierName];

  let poText = `PURCHASE ORDER\n`;
  poText += `PO Number: PO-${poDate.replace(/-/g, '')}-${String(poNumber).padStart(3, '0')}\n`;
  poText += `Date: ${poDate}\n`;
  poText += `Supplier: ${supplierName}\n`;
  poText += `\n--- ORDER DETAILS ---\n\n`;

  for (const item of supplierData.items) {
    const urgencyFlag = item.urgency === 'critical' ? ' [CRITICAL]' : (item.urgency === 'high' ? ' [HIGH]' : '');
    poText += `SKU: ${item.sku}${urgencyFlag}\n`;
    poText += `Item: ${item.name}\n`;
    poText += `Quantity: ${item.suggested_order_qty} units\n`;
    poText += `Unit Cost: $${item.unit_cost.toFixed(2)}\n`;
    poText += `Line Total: $${item.estimated_po_value.toFixed(2)}\n`;
    poText += `Reason: ${item.reasoning}\n`;
    poText += `\n`;
  }

  poText += `--- SUMMARY ---\n`;
  poText += `Total Items: ${supplierData.items.length}\n`;
  poText += `Order Total: $${supplierData.subtotal.toFixed(2)}\n`;
  poText += `\nPlease confirm receipt and expected delivery date.\n`;
  poText += `\nRegards,\nInventory Management System`;

  pos.push({
    po_number: `PO-${poDate.replace(/-/g, '')}-${String(poNumber).padStart(3, '0')}`,
    supplier: supplierName,
    supplier_email: supplierData.supplier_email,
    po_text: poText,
    item_count: supplierData.items.length,
    subtotal: supplierData.subtotal,
    items: supplierData.items
  });

  poNumber++;
}

// Return the first PO for the Gmail node (we'll send to first supplier as demo)
const firstPO = pos.length > 0 ? pos[0] : null;

return [{
  json: {
    ...data,
    all_pos: pos,
    po_count: pos.length,
    first_po: firstPO,
    email_subject: firstPO ? `Purchase Order ${firstPO.po_number} - ${firstPO.supplier}` : 'No PO',
    email_to: firstPO ? firstPO.supplier_email : '',
    email_body: firstPO ? firstPO.po_text : ''
  }
}];

// Final summary node - return complete execution report
const data = $('Parse AI Response').item.json;
const poData = $('Format PO by Supplier').item.json;

return [{
  json: {
    status: 'completed',
    message: 'Inventory reorder process completed successfully',
    summary: {
      date: data.date,
      trigger: data.trigger,
      total_skus_analyzed: data.total_skus,
      items_needing_reorder: data.reorder_count,
      critical_items: data.critical_count,
      total_po_value: data.total_po_value,
      suppliers_contacted: poData.po_count,
      ai_analysis: data.analysis_summary,
      ai_tokens_used: data.ai_tokens_used
    },
    purchase_orders: poData.all_pos,
    notifications: {
      email_sent: true,
      sheets_logged: true,
      slack_notified: true
    }
  }
}];

// All stock levels are nominal - no reorders needed
const data = $('Parse AI Response').item.json;

return [{
  json: {
    status: 'completed',
    message: 'All stock levels are nominal - no reorders needed',
    summary: {
      date: data.date,
      trigger: data.trigger,
      total_skus_analyzed: data.total_skus,
      items_needing_reorder: 0,
      ai_analysis: data.analysis_summary || 'All items above reorder threshold'
    }
  }
}];

// Format error details for logging and notification
const errorData = $input.first().json;

const errorInfo = {
  timestamp: new Date().toISOString(),
  workflow: errorData.workflow ? errorData.workflow.name : 'Unknown',
  execution_id: errorData.execution ? errorData.execution.id : 'Unknown',
  node: errorData.execution && errorData.execution.lastNodeExecuted ? errorData.execution.lastNodeExecuted : 'Unknown',
  error_message: errorData.execution && errorData.execution.error && errorData.execution.error.message ? errorData.execution.error.message : 'Unknown error',
  error_stack: errorData.execution && errorData.execution.error && errorData.execution.error.stack ? errorData.execution.error.stack.substring(0, 500) : ''
};

const slackMessage = `:rotating_light: *Workflow Error Alert*\n\n*Workflow:* ${errorInfo.workflow}\n*Node:* ${errorInfo.node}\n*Time:* ${errorInfo.timestamp}\n*Error:* ${errorInfo.error_message}`;

return [{
  json: {
    ...errorInfo,
    slack_message: slackMessage
  }
}];
